mapper.select:
SELECT id, demand_id, title, type, category, urgency, status, user_id, company_name, contact_name, contact_phone, email, location, description, specifications, budget, deadline, publish_date, tags, requirements, view_count, created_at, updated_at FROM supply_demands WHERE 1=1
AND (title LIKE CONCAT('%', #{keyword}, '%') OR description LIKE CONCAT('%', #{keyword}, '%') OR company_name LIKE CONCAT('%', #{keyword}, '%') OR tags LIKE CONCAT('%', #{keyword}, '%'))
AND type = #{type}
AND urgency = #{urgency}
AND status = #{status}
ORDER BY publish_date DESC, created_at DESC

mapper.update:
UPDATE supply_demands
SET view_count = view_count + 1
WHERE id = #{id}
